<?php
namespace App\Modules\Hr\Compensation\Actions;use App\Modules\Hr\Compensation\Models\HrBenefit;use App\Modules\Hr\Compensation\Models\HrEmployeeBenefit;use App\Modules\Hr\Core\Services\HrAuditService;use App\Modules\Hr\Core\Services\TenantContext;use App\Modules\Hr\Personnel\Models\HrEmployee;
class ManageBenefitAction{public function __construct(private HrAuditService $audit){}public function create(array $data):HrBenefit{abort_unless(auth()->user()?->hasHrPermission('hr.salary.manage'),403);$tenant=app(TenantContext::class)->getId();$code=strtoupper(trim((string)($data['code']??'')));abort_if($code===''||blank($data['name']??null)||!in_array($data['type']??null,['meal','transport','insurance','bonus','other'],true),422);abort_if(HrBenefit::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->where('code',$code)->exists(),422,'Yan hak kodu kullanılıyor.');$row=HrBenefit::create(['legal_entity_id'=>$tenant,'code'=>$code,'name'=>trim($data['name']),'type'=>$data['type'],'employer_cost_encrypted'=>isset($data['employer_cost'])?(string)(float)$data['employer_cost']:null,'currency'=>'TRY','is_active'=>true]);$this->audit->log('benefit_created',$row,null,['employer_cost'=>'[MASKED]']);return $row;}public function assign(HrEmployee $employee,HrBenefit $benefit,string $startsOn,?float $contribution=null):HrEmployeeBenefit{$tenant=app(TenantContext::class)->getId();abort_unless(auth()->user()?->hasHrPermission('hr.salary.manage'),403);abort_unless($employee->legal_entity_id===$tenant&&$benefit->legal_entity_id===$tenant&&$benefit->is_active,404);$row=HrEmployeeBenefit::create(['legal_entity_id'=>$tenant,'employee_id'=>$employee->id,'benefit_id'=>$benefit->id,'starts_on'=>$startsOn,'status'=>'active','employee_contribution_encrypted'=>$contribution===null?null:(string)$contribution,'created_by'=>auth()->id()]);$this->audit->log('employee_benefit_assigned',$row,null,['contribution'=>'[MASKED]']);return $row;}}
